INSERT INTO `system_notice` (`id`,`title`,`content`,`notice_type`,`push_scope`,`target_campus_ids`,`is_top`,`publisher_id`,`publish_time`,`view_count`,`status`) VALUES (1,'关于龙子湖校区一区停水通知','各位同学：因水泵房检修，龙子湖校区一区将于6月25日8:00-12:00暂停供水，请提前做好储水准备。带来不便敬请谅解。','WATER_STOP','CAMPUS','[1]',1,1,'2026-06-16 10:00:00',153,1);
INSERT INTO `system_notice` (`id`,`title`,`content`,`notice_type`,`push_scope`,`target_campus_ids`,`is_top`,`publisher_id`,`publish_time`,`view_count`,`status`) VALUES (2,'关于开展宿舍安全卫生检查的通知','按照学校统一部署，定于6月28日对三校区学生宿舍进行安全卫生检查，请各位同学提前整理好内务，严禁使用违规电器。','SAFETY_CHECK','ALL',NULL,1,1,'2026-06-20 10:00:00',282,1);
INSERT INTO `system_notice` (`id`,`title`,`content`,`notice_type`,`push_scope`,`target_campus_ids`,`is_top`,`publisher_id`,`publish_time`,`view_count`,`status`) VALUES (3,'关于暑假期间宿舍管理安排的通知','2026年暑假期间（7月10日-8月28日），学校将对各校区宿舍进行集中维修，留校学生需提前在系统内提交留宿申请。','HOLIDAY','ALL',NULL,0,1,'2026-06-07 10:00:00',72,1);
INSERT INTO `system_notice` (`id`,`title`,`content`,`notice_type`,`push_scope`,`target_campus_ids`,`is_top`,`publisher_id`,`publish_time`,`view_count`,`status`) VALUES (4,'关于花园校区北苑临时停电通知','接供电局通知，花园校区北苑将于7月1日14:00-16:00临时停电进行线路检修，请北苑同学提前做好准备。','POWER_STOP','CAMPUS','[30, 31, 32, 33, 34, 35]',0,1,'2026-06-21 10:00:00',21,1);
INSERT INTO `system_notice` (`id`,`title`,`content`,`notice_type`,`push_scope`,`target_campus_ids`,`is_top`,`publisher_id`,`publish_time`,`view_count`,`status`) VALUES (5,'关于2026年空调租赁续费的通知','2026-2027学年空调租赁续费已开始，请需要续租的同学在7月15日前通过本平台完成缴费，逾期将停止空调使用。','AC_RENTAL','ALL',NULL,0,1,'2026-06-08 10:00:00',229,1);
INSERT INTO `system_notice` (`id`,`title`,`content`,`notice_type`,`push_scope`,`target_campus_ids`,`is_top`,`publisher_id`,`publish_time`,`view_count`,`status`) VALUES (6,'江淮校区善水书院启用通知','江淮校区善水书院即日起正式向全体师生开放，提供自习室、活动室、心理驿站等服务，开放时间：每日8:00-22:00。','OTHER','ALL',NULL,0,1,'2026-06-04 10:00:00',50,1);
